List<List<int>> solve(int seq, int sub) {
  Map<int, List<List<int>>> memo = {};
  memo[0] = [[]];
  memo[1] = [[], [0]];
  for (int i = 2; i <= seq; i++) {
    memo[i] = [for (List<int> subsequence in memo[i-1]) if (subsequence.length < sub) [...subsequence, i-1] else []]..addAll(memo[i-1].map((subsequence) => [...subsequence, i-1]));
